import React, { useState } from 'react';
import { 
  Box, 
  Typography, 
  Paper, 
  Button,
  alpha,
  useTheme,
  Avatar,
  Chip,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Tooltip,
  Link
} from '@mui/material';
import { styled } from '@mui/material/styles';
import { 
  AccountBalanceWallet, 
  AddCircleOutline, 
  Payment,
  ChevronRight,
  Close,
  ContentCopy,
  LinkOff,
  QrCode2,
  Link as LinkIcon,
  MonetizationOn
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';

// Стили компонентов
const BalanceCard = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(2.5),
  boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
  marginBottom: theme.spacing(3),
  background: `linear-gradient(135deg, ${alpha(theme.palette.primary.main, 0.08)} 0%, ${alpha(theme.palette.primary.dark, 0.05)} 100%)`,
  border: `1px solid ${alpha(theme.palette.primary.main, 0.1)}`,
  overflow: 'hidden',
  position: 'relative',
}));

const BalanceInfo = styled(Box)(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  position: 'relative',
  zIndex: 1,
}));

const WalletSection = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  marginBottom: theme.spacing(2),
}));

const BalanceAmount = styled(Box)(({ theme }) => ({
  fontWeight: 700,
  fontSize: '1.7rem',
  marginTop: theme.spacing(0.5),
  marginBottom: theme.spacing(2),
  display: 'flex',
  alignItems: 'center',
  gap: theme.spacing(1),
}));

const BalanceActions = styled(Box)(({ theme }) => ({
  display: 'flex',
  gap: theme.spacing(1.5),
  marginTop: theme.spacing(1),
}));

const QuickAction = styled(Button)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(1, 2.5),
  fontWeight: 600,
  textTransform: 'none',
  boxShadow: '0 4px 10px rgba(0,0,0,0.05)',
  '&:hover': {
    boxShadow: '0 6px 15px rgba(0,0,0,0.1)',
    transform: 'translateY(-2px)',
  }
}));

const ConnectWalletButton = styled(Button)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(1, 2.5),
  fontWeight: 600,
  textTransform: 'none',
  marginTop: theme.spacing(1.5),
  boxShadow: '0 4px 10px rgba(0,0,0,0.05)',
  '&:hover': {
    boxShadow: '0 6px 15px rgba(0,0,0,0.1)',
    transform: 'translateY(-2px)',
  }
}));

const WalletAddressChip = styled(Chip)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(0.5),
  fontWeight: 500,
  fontSize: '0.85rem',
  height: 36,
  background: alpha(theme.palette.background.paper, 0.7),
  backdropFilter: 'blur(8px)',
  border: `1px solid ${alpha(theme.palette.primary.main, 0.2)}`,
}));

const WalletCircle = styled(Box)(({ theme }) => ({
  position: 'absolute',
  top: '-50px',
  right: '-50px',
  width: '150px',
  height: '150px',
  borderRadius: '50%',
  background: alpha(theme.palette.primary.main, 0.05),
  zIndex: 0,
}));

const WalletCircleSmall = styled(Box)(({ theme }) => ({
  position: 'absolute',
  bottom: '-30px',
  left: '10%',
  width: '100px',
  height: '100px',
  borderRadius: '50%',
  background: alpha(theme.palette.primary.main, 0.03),
  zIndex: 0,
}));

// Иконка для TON вместо внешнего SVG
const TonIcon = styled(MonetizationOn)(({ theme }) => ({
  color: theme.palette.primary.main,
  fontSize: 22,
  marginRight: theme.spacing(0.5),
}));

interface WalletWidgetProps {
  balance: number;
}

const WalletWidget: React.FC<WalletWidgetProps> = ({ balance }) => {
  const theme = useTheme();
  const navigate = useNavigate();
  const [isTonConnected, setIsTonConnected] = useState(false);
  const [connectDialogOpen, setConnectDialogOpen] = useState(false);
  const [copyTooltip, setCopyTooltip] = useState("Копировать адрес");
  const [walletAddress, setWalletAddress] = useState("EQDZr7KDKG0R4Kyaxx4OgxQtECdZVV-G3vmp8rNQrCXIgnCj");

  // Имитируем сокращенный адрес кошелька для отображения
  const shortAddress = walletAddress.slice(0, 8) + "..." + walletAddress.slice(-6);
  
  const handleNavigateToWallet = () => {
    navigate('/wallet');
  };
  
  const handleTopUp = () => {
    navigate('/wallet');
  };
  
  const handleViewHistory = () => {
    navigate('/wallet');
  };

  const handleConnectDialogOpen = () => {
    setConnectDialogOpen(true);
  };

  const handleConnectDialogClose = () => {
    setConnectDialogOpen(false);
  };

  const handleConnectWallet = () => {
    // Здесь будет логика подключения кошелька TonSpace
    setIsTonConnected(true);
    handleConnectDialogClose();
  };

  const handleDisconnectWallet = () => {
    setIsTonConnected(false);
  };

  const handleCopyAddress = () => {
    navigator.clipboard.writeText(walletAddress);
    setCopyTooltip("Скопировано!");
    setTimeout(() => setCopyTooltip("Копировать адрес"), 2000);
  };
  
  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
    >
      <BalanceCard>
        <WalletCircle />
        <WalletCircleSmall />
        
        <WalletSection>
          <Box sx={{ display: 'flex', alignItems: 'center' }}>
            <AccountBalanceWallet 
              color="primary" 
              sx={{ mr: 1, fontSize: 26 }} 
            />
            <Typography variant="h6" fontWeight={600}>
              Кошелек
            </Typography>
          </Box>
          
          {isTonConnected ? (
            <Tooltip title={copyTooltip}>
              <WalletAddressChip
                icon={<TonIcon />}
                label={shortAddress}
                onClick={handleCopyAddress}
                onDelete={handleDisconnectWallet}
                deleteIcon={<LinkOff />}
              />
            </Tooltip>
          ) : (
            <QuickAction
              variant="outlined"
              color="primary"
              size="small"
              startIcon={<LinkIcon />}
              onClick={handleConnectDialogOpen}
            >
              Привязать кошелек
            </QuickAction>
          )}
        </WalletSection>
        
        <BalanceInfo>
          <Typography variant="body2" color="text.secondary">
            Ваш баланс
          </Typography>
          
          <Box display="flex" alignItems="center" sx={{ fontWeight: 700, fontSize: '1.7rem', mb: 2, mt: 0.5 }}>
            {balance.toLocaleString()} ₽
            {isTonConnected && (
              <Box component="span" ml={1}>
                <Chip 
                  size="small" 
                  label="+ 1.25 TON" 
                  color="primary" 
                  variant="outlined"
                  sx={{ 
                    fontWeight: 600, 
                    fontSize: '0.8rem',
                    height: 24,
                    border: `1px solid ${alpha(theme.palette.primary.main, 0.5)}`
                  }} 
                />
              </Box>
            )}
          </Box>
          
          <BalanceActions>
            <QuickAction
              variant="contained"
              color="primary"
              startIcon={<AddCircleOutline />}
              onClick={handleTopUp}
            >
              Пополнить
            </QuickAction>
            <QuickAction
              variant="outlined"
              startIcon={<Payment />}
              onClick={handleViewHistory}
            >
              История
            </QuickAction>
            <QuickAction
              variant="text"
              color="primary"
              endIcon={<ChevronRight />}
              onClick={handleNavigateToWallet}
              sx={{ ml: 'auto' }}
            >
              Подробнее
            </QuickAction>
          </BalanceActions>
        </BalanceInfo>
      </BalanceCard>
      
      {/* Диалог подключения кошелька TON Space */}
      <Dialog 
        open={connectDialogOpen} 
        onClose={handleConnectDialogClose}
        PaperProps={{
          sx: {
            borderRadius: 3,
            maxWidth: 400,
            padding: 1
          }
        }}
      >
        <DialogTitle sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', pb: 1 }}>
          <Box sx={{ display: 'flex', alignItems: 'center' }}>
            <TonIcon sx={{ fontSize: 28, mr: 1 }} />
            <Typography variant="h6" component="div" fontWeight={600}>
              Подключить TON Space
            </Typography>
          </Box>
          <IconButton size="small" onClick={handleConnectDialogClose}>
            <Close />
          </IconButton>
        </DialogTitle>
        
        <DialogContent>
          <Typography variant="body2" sx={{ mb: 2 }}>
            Привяжите кошелек TON Space для доступа к криптовалютным транзакциям и NFT прямо из приложения.
          </Typography>
          
          <Box sx={{ display: 'flex', justifyContent: 'center', my: 2 }}>
            <QrCode2 sx={{ fontSize: 120, color: alpha(theme.palette.primary.main, 0.8) }} />
          </Box>
          
          <Typography variant="body2" sx={{ textAlign: 'center', mb: 1 }}>
            Отсканируйте QR-код в приложении TON Space или подключитесь через браузерное расширение
          </Typography>
          
          <Box sx={{ textAlign: 'center', mt: 2 }}>
            <Link 
              href="https://tonspace.net" 
              target="_blank" 
              underline="hover" 
              color="primary"
              sx={{ fontWeight: 500, fontSize: '0.9rem' }}
            >
              Узнать больше о TON Space
            </Link>
          </Box>
        </DialogContent>
        
        <DialogActions sx={{ justifyContent: 'center', pb: 2 }}>
          <ConnectWalletButton 
            variant="contained" 
            color="primary" 
            onClick={handleConnectWallet}
            startIcon={<TonIcon />}
          >
            Подключить кошелек
          </ConnectWalletButton>
        </DialogActions>
      </Dialog>
    </motion.div>
  );
};

export default WalletWidget;
